SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT c.CODE_GROUP_ID AS codeGroupId, c.CODE AS code, c.CODE_NAME AS codeName, c.CODE_DESC AS codeDesc, c.SORT_ORDER AS sortOrder, c.USE_YN AS useYn, c.CODE_ENGNAME AS codeEngname, c.LAST_UPDATE_DTIME AS lastUpdateDtime, c.LAST_UPDATE_USER_ID AS lastUpdateUserId, cg.CODE_GROUP_NAME AS codeGroupName FROM FWK_CODE c INNER JOIN FWK_CODE_GROUP cg ON c.CODE_GROUP_ID = cg.CODE_GROUP_ID
ORDER BY c.CODE_GROUP_ID ORDER BY cg.CODE_GROUP_NAME ORDER BY c.CODE ORDER BY c.CODE_NAME ORDER BY c.CODE_DESC ORDER BY c.SORT_ORDER ORDER BY c.USE_YN ORDER BY c.CODE_GROUP_ID, c.SORT_ORDER
DESC ASC
ORDER BY c.CODE_GROUP_ID, c.SORT_ORDER
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
